mapper.select:
select document_link_id, company_id, source_document_id, target_document_id, link_type, status, created_by, created_at
from document_links
where document_link_id = #{documentLinkId,jdbcType=VARCHAR}

select document_link_id, company_id, source_document_id, target_document_id, link_type, status, created_by, created_at
from document_links
where company_id = #{companyId,jdbcType=VARCHAR}
  and source_document_id = #{sourceDocumentId,jdbcType=VARCHAR}
  and upper(coalesce(trim(status), '')) = 'ACTIVE'
order by created_at desc
limit #{limit,jdbcType=INTEGER}

select document_link_id, company_id, source_document_id, target_document_id, link_type, status, created_by, created_at
from document_links
where company_id = #{companyId,jdbcType=VARCHAR}
  and target_document_id = #{targetDocumentId,jdbcType=VARCHAR}
  and upper(coalesce(trim(status), '')) = 'ACTIVE'
order by created_at desc
limit #{limit,jdbcType=INTEGER}
